#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int** edges = (int**)malloc(M * sizeof(int*));
        for (int i = 0; i < M; i++) {
            edges[i] = (int*)malloc(2 * sizeof(int));
            scanf("%d %d", &edges[i][0], &edges[i][1]);
        }
        int intersections = 0;
        printf("%d\n", intersections);
        int x = 1;
        int y = 1;
        for (int i = 1; i <= N; i++) {
            if (i % 4 == 1) {
                printf("%d %d\n", x, y);
                x++;
            } else if (i % 4 == 2) {
                printf("%d %d\n", -x, y);
                x++;
            } else if (i % 4 == 3) {
                printf("%d %d\n", -x, -y);
                x++;
            } else {
                printf("%d %d\n", x, -y);
                x++;
            }
        }
        for (int i = 0; i < M; i++) {
            free(edges[i]);
        }
        free(edges);
    }
    return 0;
}

