#include <iostream>
using namespace std;

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N, M;
        cin >> N >> M;
        int** edges = new int*[M];
        for (int i = 0; i < M; i++) {
            edges[i] = new int[2];
            cin >> edges[i][0] >> edges[i][1];
        }
        int intersections = 0;
        cout << intersections << endl;
        int x = 1;
        int y = 1;
        for (int i = 1; i <= N; i++) {
            if (i % 4 == 1) {
                cout << x << " " << y << endl;
                x++;
            } else if (i % 4 == 2) {
                cout << -x << " " << y << endl;
                x++;
            } else if (i % 4 == 3) {
                cout << -x << " " << -y << endl;
                x++;
            } else {
                cout << x << " " << -y << endl;
                x++;
            }
        }
        for (int i = 0; i < M; i++) {
            delete[] edges[i];
        }
        delete[] edges;
    }
    return 0;
}

